const d = $input.first().json;
if (!d.email || !d.instagram) throw new Error('Missing required fields: email and instagram are required');

d.followers = parseInt(d.followers) || 0;
d.applied_at = new Date().toISOString();
d.status = 'pending_review';

// Normalizar instagram handle (quitar @ si viene con prefijo)
d.instagram = (d.instagram || '').replace('@', '').trim();
d.tiktok = (d.tiktok || '').replace('@', '').trim() || null;

// Normalizar email
d.email = d.email.toLowerCase().trim();

// Normalizar telefono
let phone = (d.phone || '').replace(/\D/g, '');
if (phone && phone.length === 10) phone = '57' + phone;
d.phone = phone || null;

return [{ json: d }];

