// FIX H7: Parseo robusto con try/catch y guards en cada acceso.
const input = $input.first().json;

// Buscar bloque de tipo text (no asumir content[0])
const block = input?.content?.find(b => b.type === 'text');
if (!block?.text) {
  // FIX H7: No lanzar error que abort el workflow — insertar con score=null
  console.warn('[creator-scoring] Claude sin text block:', JSON.stringify(input).slice(0, 300));
  const creator = $('Code - Validate Creator').item.json;
  return [{ json: { ...creator, score: null, ai_notes: JSON.stringify({ error: 'Claude sin text block', raw: input }), status: 'scoring_failed' } }];
}

// FIX H7: Guard en match — si null, fallback en lugar de crash
const match = block.text.match(/\{[\s\S]*?\}/);
if (!match) {
  console.warn('[creator-scoring] No JSON en respuesta:', block.text.slice(0, 300));
  const creator = $('Code - Validate Creator').item.json;
  return [{ json: { ...creator, score: null, ai_notes: JSON.stringify({ error: 'No JSON', raw: block.text.slice(0, 500) }), status: 'scoring_failed' } }];
}

let score;
try {
  score = JSON.parse(match[0]);
} catch (e) {
  console.warn('[creator-scoring] JSON invalido:', match[0].slice(0, 200), e.message);
  const creator = $('Code - Validate Creator').item.json;
  return [{ json: { ...creator, score: null, ai_notes: JSON.stringify({ error: e.message, raw: match[0].slice(0, 300) }), status: 'scoring_failed' } }];
}

const creator = $('Code - Validate Creator').item.json;
return [{ json: {
  ...creator,
  score: typeof score.score === 'number' ? score.score : null,
  ai_notes: JSON.stringify(score),
  status: creator.status  // mantener 'pending_review'
} }];

